//! Long-form workspace CLI help text constants.

pub(crate) const SYNC_ROOT_HELP_TEXT: &str = "Examples:\n\n  Scan one repo root that carries source provenance for Git Sync dashboards, access bundles, alerts/raw, and datasources/provisioning:\n    grafana-util workspace scan ./grafana-oac-repo --output-format table\n\n  Example mixed workspace tree:\n    ./grafana-oac-repo/\n      dashboards/git-sync/raw/\n      dashboards/git-sync/provisioning/\n      access-users/\n      access-teams/\n      access-orgs/\n      access-service-accounts/\n      alerts/raw/\n      datasources/provisioning/datasources.yaml\n\n  Test whether the staged package looks safe to continue:\n    grafana-util workspace test ./grafana-oac-repo --output-format json\n\n  Preview what would change against live Grafana:\n    grafana-util workspace preview ./grafana-oac-repo --fetch-live --profile prod --output-format json\n\n  Package the same mixed workspace into one handoff file:\n    grafana-util workspace package ./grafana-oac-repo --output-file ./workspace-package.json\n\n  Apply a reviewed workspace back to Grafana:\n    grafana-util workspace apply --approve --execute-live --profile prod\n\nCI workflows:\n\n  Test a workspace package against target inventory before apply:\n    grafana-util workspace ci package-test --source-bundle ./workspace-package.json --target-inventory ./target-inventory.json --output-format json\n\n  Test a staged promotion handoff:\n    grafana-util workspace ci promote-test --source-bundle ./workspace-package.json --target-inventory ./target-inventory.json --mapping-file ./promotion-map.json --output-format json";
pub(crate) const SYNC_SCAN_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace scan ./grafana-oac-repo --output-format table\n  grafana-util workspace scan ./grafana-oac-repo --dashboard-export-dir ./dashboards/raw --alert-export-dir ./alerts/raw --output-format json\n\n  Mixed workspace tree:\n    ./grafana-oac-repo/\n      dashboards/git-sync/raw/\n      dashboards/git-sync/provisioning/\n      access-users/\n      access-teams/\n      access-orgs/\n      access-service-accounts/\n      alerts/raw/\n      datasources/provisioning/datasources.yaml";
pub(crate) const SYNC_TEST_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace test ./grafana-oac-repo --output-format json\n  grafana-util workspace test ./grafana-oac-repo --dashboard-provisioning-dir ./dashboards/provisioning --output-format table\n\n  Same mixed workspace root can carry dashboard, access, alert, and datasource provenance together.";
pub(crate) const SYNC_PREVIEW_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace preview ./grafana-oac-repo --fetch-live --profile prod --output-format json\n  grafana-util workspace preview ./grafana-oac-repo --desired-file ./desired.json --live-file ./live.json\n  grafana-util workspace preview ./grafana-oac-repo --dashboard-export-dir ./dashboards/raw --alert-export-dir ./alerts/raw --fetch-live --profile prod --output-file ./workspace-preview.json\n\n  Preview the same mixed workspace root when dashboards, alerts, and datasources live under one repo tree.";
pub(crate) const SYNC_SUMMARY_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace ci summary --desired-file ./desired.json\n  grafana-util workspace ci summary --desired-file ./desired.json --output-format json";
