pub(crate) const SYNC_REVIEW_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace ci mark-reviewed --plan-file ./workspace-plan.json\n  grafana-util workspace ci mark-reviewed --plan-file ./workspace-plan.json --review-note 'peer-reviewed' --output-format json";
