pub(crate) const SYNC_BUNDLE_PREFLIGHT_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace ci package-test --source-bundle ./workspace-package.json --target-inventory ./target.json\n  grafana-util workspace ci package-test --source-bundle ./workspace-package.json --target-inventory ./target.json --availability-file ./availability.json --output-format json\n\n  Example availability file:\n    {\n      \"providerNames\": [\"vault\"],\n      \"secretPlaceholderNames\": [\"prom-basic-auth\"]\n    }";
pub(crate) const SYNC_PROMOTION_PREFLIGHT_HELP_TEXT: &str = "This command is a staged review handoff for promotion; it stays read-only and does not apply live changes.\n\nExamples:\n\n  grafana-util workspace ci promote-test --source-bundle ./workspace-package.json --target-inventory ./target.json\n  grafana-util workspace ci promote-test --source-bundle ./workspace-package.json --target-inventory ./target.json --mapping-file ./promotion-mapping.json --availability-file ./availability.json --output-format json\n\n  Minimal promotion mapping file:\n    {\n      \"kind\": \"grafana-utils-sync-promotion-mapping\",\n      \"schemaVersion\": 1,\n      \"metadata\": {\n        \"sourceEnvironment\": \"staging\",\n        \"targetEnvironment\": \"prod\"\n      },\n      \"folders\": {\n        \"ops-src\": \"ops-prod\"\n      },\n      \"datasources\": {\n        \"uids\": {\n          \"prom-src\": \"prom-prod\"\n        },\n        \"names\": {\n          \"Prometheus Source\": \"Prometheus Prod\"\n        }\n      }\n    }\n\n  Example availability file:\n    {\n      \"providerNames\": [\"vault\"],\n      \"secretPlaceholderNames\": [\"prom-basic-auth\"]\n    }";
pub(crate) const SYNC_PACKAGE_HELP_TEXT: &str = "Examples:\n\n  grafana-util workspace package ./grafana-oac-repo --dashboard-export-dir ./dashboards/raw --alert-export-dir ./alerts/raw --output-file ./workspace-package.json\n  grafana-util workspace package ./grafana-oac-repo --dashboard-export-dir ./dashboards/raw --datasource-export-file ./datasources/datasources.json --output-format json\n  grafana-util workspace package ./grafana-oac-repo --dashboard-export-dir ./dashboards/raw --datasource-provisioning-file ./datasources/provisioning/datasources.yaml --output-format json\n  grafana-util workspace package ./grafana-oac-repo --dashboard-provisioning-dir ./dashboards/provisioning --alert-export-dir ./alerts/raw --output-file ./workspace-package.json\n  grafana-util workspace package ./grafana-oac-repo --output-file ./workspace-package.json\n\n  Mixed workspace package handoff:\n    use one repo root that carries dashboards/git-sync/raw, dashboards/git-sync/provisioning,\n    alerts/raw, and datasources/provisioning/datasources.yaml, then package the surfaced\n    dashboards, alerts, and datasource provenance into ./workspace-package.json.";
